     1→import React, { useState, useRef, useMemo, useEffect } from 'react';
     2→import {
     3→  DndContext,
     4→  DragOverlay,
     5→  PointerSensor,
     6→  TouchSensor,
     7→  useSensor,
     8→  useSensors,
     9→  closestCorners,
    10→  type DragEndEvent,
    11→  type DragStartEvent,
    12→} from '@dnd-kit/core';
    13→import { Widget } from '../components/Widget';
    14→import { KeyboardShortcutsHelp } from '../components/KeyboardShortcutsHelp';
    15→import { ConfirmDialog } from '../components/ConfirmDialog';
    16→import { Toast } from '../components/Toast';
    17→import { useKanbanStore } from '../stores/useKanbanStore';
    18→import { useSettingsStore } from '../stores/useSettingsStore';
    19→import { useKanbanKeyboard } from '../hooks/useKanbanKeyboard';
    20→import { KanbanColumn } from './Kanban/KanbanColumn';
    21→import { KanbanCard } from './Kanban/KanbanCard';
    22→import { ColumnManager } from './Kanban/ColumnManager';
    23→import { CardDetailPanel } from './Kanban/CardDetailPanel';
    24→import { ListView } from './Kanban/ListView';
    25→import { CalendarView } from './Kanban/CalendarView';
    26→import { ArchivedView } from './Kanban/ArchivedView';
    27→import { QuickAddModal } from './Kanban/QuickAddModal';
    28→import type { Task, TaskStatus } from '../types';
    29→
    30→/**
    31→ * Kanban Board Widget - React Version with Drag & Drop
    32→ *
    33→ * Features:
    34→ * - Three-column board (To Do, In Progress, Done)
    35→ * - Drag and drop tasks between columns
    36→ * - Task CRUD operations
    37→ * - Priority and due date tracking
    38→ * - Syncs with Calendar widget
    39→ * - Keyboard shortcuts for navigation and actions
    40→ */
    41→export const Kanban: React.FC = () => {
    42→  const { tasks, columns, moveTask, deleteTask, updateTask, undo, undoHistory, autoArchiveCompletedTasks, visibleColumns = 5, setVisibleColumns } = useKanbanStore();
    43→  const [activeTask, setActiveTask] = useState<Task | null>(null);
    44→  const [showColumnManager, setShowColumnManager] = useState(false);
    45→  const [columnManagerInitialId, setColumnManagerInitialId] = useState<string | undefined>();
    46→  const [showArchivedView, setShowArchivedView] = useState(false);
    47→  const [showQuickAdd, setShowQuickAdd] = useState(false);
    48→  const [toast, setToast] = useState<{ message: string; showUndo: boolean } | null>(null);
    49→  const [detailPanelTaskId, setDetailPanelTaskId] = useState<string | null>(null);
    50→  const [selectedTab, setSelectedTab] = useState<'subtasks' | 'checklist' | 'comments' | 'activity'>('subtasks');
    51→
    52→  // Get the current task from the store (reactive)
    53→  const selectedTask = detailPanelTaskId ? tasks.find(t => t.id === detailPanelTaskId) || null : null;
    54→
    55→  // View mode state with persistence
    56→  const [viewMode, setViewMode] = useState<'board' | 'list' | 'calendar'>(() => {
    57→    const saved = localStorage.getItem('kanban-view-mode');
    58→    return (saved as 'board' | 'list' | 'calendar') || 'board';
    59→  });
    60→
    61→  // Filter state
    62→  const [searchQuery, setSearchQuery] = useState('');
    63→  const [selectedPriorities, setSelectedPriorities] = useState<Set<string>>(new Set());
    64→  const [selectedTags, setSelectedTags] = useState<Set<string>>(new Set());
    65→  const [selectedAssignees, setSelectedAssignees] = useState<Set<string>>(new Set());
    66→  const [showUnassigned, setShowUnassigned] = useState(false);
    67→  const [showFilters, setShowFilters] = useState(false);
    68→
    69→  // Phase 3.1: Get members for assignee filter
    70→  const members = useSettingsStore((state) => state.members);
    71→
    72→  // Refs for columns to trigger their add forms
    73→  const columnRefs = useRef<Record<string, { triggerAdd: () => void }>>({});
    74→  const cardRefs = useRef<Record<string, { triggerEdit: () => void }>>({});
    75→
    76→  // Configure sensors for drag-drop (mouse + touch)
    77→  const sensors = useSensors(
    78→    useSensor(PointerSensor, {
    79→      activationConstraint: {
    80→        distance: 8, // 8px movement before drag starts
    81→      },
    82→    }),
    83→    useSensor(TouchSensor, {
    84→      activationConstraint: {
    85→        delay: 250, // 250ms long press
    86→        tolerance: 5, // 5px movement tolerance
    87→      },
    88→    })
    89→  );
    90→
    91→  // Sort columns by order
    92→  const sortedColumns = useMemo(() => {
    93→    return [...columns].sort((a, b) => a.order - b.order);
    94→  }, [columns]);
    95→
    96→  const columnStatuses = sortedColumns.map((col) => col.id);
    97→
    98→  // Get all unique tags from tasks
    99→  const allTags = useMemo(() => {
   100→    const tagSet = new Set<string>();
   101→    tasks.forEach((task) => task.tags.forEach((tag) => tagSet.add(tag)));
   102→    return Array.from(tagSet).sort();
   103→  }, [tasks]);
   104→
   105→  // Filter tasks based on search and filters
   106→  const filteredTasks = useMemo(() => {
   107→    return tasks.filter((task) => {
   108→      // Search filter (title, description, or card number)
   109→      if (searchQuery) {
   110→        const query = searchQuery.toLowerCase();
   111→
   112→        // Phase A: Support searching by card number (e.g., "KAN-1", "1", "kan1")
   113→        const cardNumberStr = task.cardNumber ? `KAN-${task.cardNumber}`.toLowerCase() : '';
   114→        const cardNumberSimple = task.cardNumber?.toString() || '';
   115→
   116→        const matchesSearch =
   117→          task.title.toLowerCase().includes(query) ||
   118→          task.description.toLowerCase().includes(query) ||
   119→          cardNumberStr.includes(query) ||
   120→          cardNumberSimple.includes(query);
   121→
   122→        if (!matchesSearch) return false;
   123→      }
   124→
   125→      // Priority filter
   126→      if (selectedPriorities.size > 0 && !selectedPriorities.has(task.priority)) {
   127→        return false;
   128→      }
   129→
   130→      // Tags filter
   131→      if (selectedTags.size > 0) {
   132→        const hasSelectedTag = task.tags.some((tag) => selectedTags.has(tag));
   133→        if (!hasSelectedTag) return false;
   134→      }
   135→
   136→      // Assignee filter (Phase 3.1)
   137→      if (selectedAssignees.size > 0 || showUnassigned) {
   138→        const taskAssignees = task.assignees || [];
   139→
   140→        // If "Unassigned" is selected
   141→        if (showUnassigned && taskAssignees.length === 0) {
   142→          return true;
   143→        }
   144→
   145→        // If specific assignees are selected
   146→        if (selectedAssignees.size > 0) {
   147→          const hasSelectedAssignee = taskAssignees.some((id) => selectedAssignees.has(id));
   148→          if (hasSelectedAssignee) return true;
   149→        }
   150→
   151→        // Neither condition met
   152→        if (selectedAssignees.size > 0 || showUnassigned) {
   153→          return false;
   154→        }
   155→      }
   156→
   157→      return true;
   158→    });
   159→  }, [tasks, searchQuery, selectedPriorities, selectedTags, selectedAssignees, showUnassigned]);
   160→
   161→  // Toggle filter helpers
   162→  const togglePriority = (priority: string) => {
   163→    setSelectedPriorities((prev) => {
   164→      const newSet = new Set(prev);
   165→      if (newSet.has(priority)) {
   166→        newSet.delete(priority);
   167→      } else {
   168→        newSet.add(priority);
   169→      }
   170→      return newSet;
   171→    });
   172→  };
   173→
   174→  const toggleTag = (tag: string) => {
   175→    setSelectedTags((prev) => {
   176→      const newSet = new Set(prev);
   177→      if (newSet.has(tag)) {
   178→        newSet.delete(tag);
   179→      } else {
   180→        newSet.add(tag);
   181→      }
   182→      return newSet;
   183→    });
   184→  };
   185→
   186→  const toggleAssignee = (memberId: string) => {
   187→    setSelectedAssignees((prev) => {
   188→      const newSet = new Set(prev);
   189→      if (newSet.has(memberId)) {
   190→        newSet.delete(memberId);
   191→      } else {
   192→        newSet.add(memberId);
   193→      }
   194→      return newSet;
   195→    });
   196→  };
   197→
   198→  const clearFilters = () => {
   199→    setSearchQuery('');
   200→    setSelectedPriorities(new Set());
   201→    setSelectedTags(new Set());
   202→    setSelectedAssignees(new Set());
   203→    setShowUnassigned(false);
   204→  };
   205→
   206→  const hasActiveFilters =
   207→    searchQuery || selectedPriorities.size > 0 || selectedTags.size > 0 || selectedAssignees.size > 0 || showUnassigned;
   208→
   209→  // Keyboard shortcuts
   210→  const {
   211→    selectedColumn,
   212→    selectedTaskId,
   213→    showHelp,
   214→    closeHelp,
   215→    pendingDeleteTask,
   216→    confirmDelete,
   217→    cancelDelete,
   218→  } = useKanbanKeyboard({
   219→    columns: columnStatuses,
   220→    tasks: filteredTasks, // Use filtered tasks for keyboard navigation
   221→    onAddTask: (status) => {
   222→      // Trigger the add form in the selected column
   223→      columnRefs.current[status]?.triggerAdd();
   224→    },
   225→    onEditTask: (task) => {
   226→      // Trigger edit mode for the selected task
   227→      cardRefs.current[task.id]?.triggerEdit();
   228→    },
   229→    onDeleteTask: (taskId) => {
   230→      deleteTask(taskId);
   231→    },
   232→  });
   233→
   234→  const handleDragStart = (event: DragStartEvent) => {
   235→    const taskId = event.active.id as string;
   236→    const task = tasks.find((t) => t.id === taskId);
   237→    setActiveTask(task || null);
   238→  };
   239→
   240→  const handleDragEnd = (event: DragEndEvent) => {
   241→    const { active, over } = event;
   242→
   243→    setActiveTask(null);
   244→
   245→    if (!over) return;
   246→
   247→    const taskId = active.id as string;
   248→    const newStatus = over.id as TaskStatus;
   249→
   250→    // WIP Limit validation (Phase 3.3)
   251→    const targetColumn = columns.find((c) => c.id === newStatus);
   252→    const currentTask = tasks.find((t) => t.id === taskId);
   253→    const tasksInTargetColumn = tasks.filter((t) => t.status === newStatus);
   254→
   255→    // Only check WIP limit if moving TO a different column (not reordering within same column)
   256→    if (targetColumn?.wipLimit && currentTask?.status !== newStatus) {
   257→      const enforceStrict = useSettingsStore.getState().enforceWipLimits;
   258→
   259→      // Check if target column is at or over WIP limit
   260→      if (tasksInTargetColumn.length >= targetColumn.wipLimit) {
   261→        if (enforceStrict) {
   262→          // Hard limit: prevent move
   263→          setToast({
   264→            message: `Cannot move task: "${targetColumn.title}" has reached WIP limit (${targetColumn.wipLimit})`,
   265→            showUndo: false,
   266→          });
   267→          return; // Abort move
   268→        } else {
   269→          // Soft limit: show warning but allow move
   270→          setToast({
   271→            message: `Warning: "${targetColumn.title}" is at/over WIP limit (${tasksInTargetColumn.length + 1}/${targetColumn.wipLimit})`,
   272→            showUndo: false,
   273→          });
   274→        }
   275→      }
   276→    }
   277→
   278→    // Move task to new column
   279→    moveTask(taskId, newStatus);
   280→  };
   281→
   282→  const handleEditColumn = (columnId: string) => {
   283→    setColumnManagerInitialId(columnId);
   284→    setShowColumnManager(true);
   285→  };
   286→
   287→  // View mode persistence
   288→  useEffect(() => {
   289→    localStorage.setItem('kanban-view-mode', viewMode);
   290→  }, [viewMode]);
   291→
   292→  // Phase A: Auto-archive completed tasks on mount
   293→  useEffect(() => {
   294→    autoArchiveCompletedTasks();
   295→  }, []); // Run once on mount
   296→
   297→  // Phase A: Global keyboard shortcut for Quick Add (Cmd/Ctrl+K)
   298→  useEffect(() => {
   299→    const handleGlobalKeyDown = (e: KeyboardEvent) => {
   300→      // Cmd/Ctrl+K to open Quick Add
   301→      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
   302→        // Don't trigger if user is typing in an input/textarea
   303→        const target = e.target as HTMLElement;
   304→        if (target.tagName === 'INPUT' || target.tagName === 'TEXTAREA' || target.isContentEditable) {
   305→          return;
   306→        }
   307→
   308→        e.preventDefault();
   309→        setShowQuickAdd(true);
   310→      }
   311→    };
   312→
   313→    window.addEventListener('keydown', handleGlobalKeyDown);
   314→    return () => window.removeEventListener('keydown', handleGlobalKeyDown);
   315→  }, []);
   316→
   317→  // Listen for undo history changes and show toast
   318→  useEffect(() => {
   319→    if (undoHistory.length > 0) {
   320→      const lastEntry = undoHistory[undoHistory.length - 1];
   321→      setToast({
   322→        message: lastEntry.description,
   323→        showUndo: true,
   324→      });
   325→    }
   326→  }, [undoHistory]);
   327→
   328→  const handleUndo = () => {
   329→    undo();
   330→    setToast(null);
   331→  };
   332→
   333→  return (
   334→    <Widget
   335→      id="kanban"
   336→      title="Kanban Board"
   337→      category="Planning"
   338→      draggable={false}
   339→      headerAccessory={
   340→        <div className="flex items-center gap-1">
   341→          <span className="text-xs text-text-light-secondary dark:text-text-dark-secondary mr-2">
   342→            Columns:
   343→          </span>
   344→          {[3, 4, 5, 6, 7].map((count) => (
   345→            <button
   346→              key={count}
   347→              onClick={() => setVisibleColumns(count)}
   348→              className={`px-2 py-1 text-xs font-medium rounded transition-colors ${
   349→                visibleColumns === count
   350→                  ? 'bg-accent-blue text-white'
   351→                  : 'bg-surface-light-elevated dark:bg-surface-dark-elevated text-text-light-secondary dark:text-text-dark-secondary hover:text-text-light-primary dark:hover:text-text-dark-primary hover:bg-neutral-200 dark:hover:bg-neutral-700'
   352→              }`}
   353→              title={`Show ${count} columns at once`}
   354→            >
   355→              {count}
   356→            </button>
   357→          ))}
   358→        </div>
   359→      }
   360→    >
   361→      {/* Filter Bar */}
   362→      <div className="mb-4 space-y-3">
   363→        {/* Search and Filter Toggle */}
   364→        <div className="flex gap-2">
   365→          <input
   366→            type="text"
   367→            value={searchQuery}
   368→            onChange={(e) => setSearchQuery(e.target.value)}
   369→            placeholder="Search tasks (by title, description, or KAN-#)..."
   370→            className="flex-1 px-4 py-2 text-sm border border-neutral-lightGray dark:border-neutral-darkGray rounded-lg bg-white dark:bg-neutral-charcoal text-text-light-primary dark:text-text-dark-primary placeholder-text-light-secondary dark:placeholder-text-dark-secondary focus:outline-none focus:ring-2 focus:ring-accent-primary"
   371→          />
   372→          <button
   373→            onClick={() => setShowColumnManager(true)}
   374→            className="px-4 py-2 text-sm font-medium bg-accent-blue text-white rounded-lg hover:bg-accent-blue-hover transition-colors whitespace-nowrap"
   375→            title="Manage Columns"
   376→          >
   377→            ⚙️ Columns
   378→          </button>
   379→          <button
   380→            onClick={() => setShowArchivedView(true)}
   381→            className="px-4 py-2 text-sm font-medium bg-surface-light-elevated dark:bg-surface-dark text-text-light-primary dark:text-text-dark-primary rounded-lg border border-border-light dark:border-border-dark hover:bg-surface-light dark:hover:bg-surface-dark-elevated transition-colors whitespace-nowrap"
   382→            title="View Archived Tasks"
   383→          >
   384→            📦 Archived
   385→          </button>
   386→          {/* View Toggle */}
   387→          <div className="flex rounded-lg overflow-hidden border border-border-light dark:border-border-dark">
   388→            <button
   389→              onClick={() => setViewMode('board')}
   390→              className={`px-3 py-2 text-sm font-medium transition-colors whitespace-nowrap ${
   391→                viewMode === 'board'
   392→                  ? 'bg-accent-blue text-white'
   393→                  : 'bg-white dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-50 dark:hover:bg-neutral-700'
   394→              }`}
   395→              title="Board View"
   396→            >
   397→              📋 Board
   398→            </button>
   399→            <button
   400→              onClick={() => setViewMode('list')}
   401→              className={`px-3 py-2 text-sm font-medium transition-colors whitespace-nowrap border-l border-border-light dark:border-border-dark ${
   402→                viewMode === 'list'
   403→                  ? 'bg-accent-blue text-white'
   404→                  : 'bg-white dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-50 dark:hover:bg-neutral-700'
   405→              }`}
   406→              title="List View"
   407→            >
   408→              📊 List
   409→            </button>
   410→            <button
   411→              onClick={() => setViewMode('calendar')}
   412→              className={`px-3 py-2 text-sm font-medium transition-colors whitespace-nowrap border-l border-border-light dark:border-border-dark ${
   413→                viewMode === 'calendar'
   414→                  ? 'bg-accent-blue text-white'
   415→                  : 'bg-white dark:bg-neutral-800 text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-50 dark:hover:bg-neutral-700'
   416→              }`}
   417→              title="Calendar View"
   418→            >
   419→              📅 Calendar
   420→            </button>
   421→          </div>
   422→          <button
   423→            onClick={() => setShowFilters(!showFilters)}
   424→            className={`px-4 py-2 text-sm font-medium rounded-lg transition-colors whitespace-nowrap ${
   425→              showFilters || hasActiveFilters
   426→                ? 'bg-accent-primary text-white'
   427→                : 'bg-neutral-paleGray dark:bg-neutral-darkGray text-text-light-secondary dark:text-text-dark-secondary hover:bg-neutral-lightGray dark:hover:bg-neutral-gray'
   428→            }`}
   429→          >
   430→            🔍 Filters {hasActiveFilters && `(${[...selectedPriorities, ...selectedTags, ...selectedAssignees].length + (showUnassigned ? 1 : 0)})`}
   431→          </button>
   432→          {hasActiveFilters && (
   433→            <button
   434→              onClick={clearFilters}
   435→              className="px-4 py-2 text-sm font-medium bg-neutral-gray text-white rounded-lg hover:opacity-80 transition-opacity"
   436→            >
   437→              Clear
   438→            </button>
   439→          )}
   440→        </div>
   441→
   442→        {/* Advanced Filters (collapsible) */}
   443→        {showFilters && (
   444→          <div className="p-4 bg-neutral-paleGray dark:bg-neutral-darkGray rounded-lg space-y-3">
   445→            {/* Priority Filter */}
   446→            <div>
   447→              <label className="block text-xs font-semibold text-text-light-secondary dark:text-text-dark-secondary mb-2 uppercase tracking-wide">
   448→                Priority
   449→              </label>
   450→              <div className="flex gap-2 flex-wrap">
   451→                {(['low', 'medium', 'high'] as const).map((priority) => (
   452→                  <button
   453→                    key={priority}
   454→                    onClick={() => togglePriority(priority)}
   455→                    className={`px-3 py-1.5 text-xs font-medium rounded-lg transition-all ${
   456→                      selectedPriorities.has(priority)
   457→                        ? 'bg-accent-primary text-white ring-2 ring-accent-primary ring-offset-2 ring-offset-white dark:ring-offset-neutral-darkGray'
   458→                        : 'bg-white dark:bg-neutral-charcoal text-text-light-secondary dark:text-text-dark-secondary border border-neutral-lightGray dark:border-neutral-gray hover:border-accent-primary'
   459→                    }`}
   460→                  >
   461→                    {priority.charAt(0).toUpperCase() + priority.slice(1)}
   462→                  </button>
   463→                ))}
   464→              </div>
   465→            </div>
   466→
   467→            {/* Tags Filter */}
   468→            {allTags.length > 0 && (
   469→              <div>
   470→                <label className="block text-xs font-semibold text-text-light-secondary dark:text-text-dark-secondary mb-2 uppercase tracking-wide">
   471→                  Tags
   472→                </label>
   473→                <div className="flex gap-2 flex-wrap">
   474→                  {allTags.map((tag) => (
   475→                    <button
   476→                      key={tag}
   477→                      onClick={() => toggleTag(tag)}
   478→                      className={`px-3 py-1.5 text-xs font-medium rounded-lg transition-all ${
   479→                        selectedTags.has(tag)
   480→                          ? 'bg-secondary-primary text-white ring-2 ring-secondary-primary ring-offset-2 ring-offset-white dark:ring-offset-neutral-darkGray'
   481→                          : 'bg-white dark:bg-neutral-charcoal text-text-light-secondary dark:text-text-dark-secondary border border-neutral-lightGray dark:border-neutral-gray hover:border-secondary-primary'
   482→                      }`}
   483→                    >
   484→                      #{tag}
   485→                    </button>
   486→                  ))}
   487→                </div>
   488→              </div>
   489→            )}
   490→
   491→            {/* Assignee Filter - Phase 3.1 */}
   492→            {members.length > 0 && (
   493→              <div>
   494→                <label className="block text-xs font-semibold text-text-light-secondary dark:text-text-dark-secondary mb-2 uppercase tracking-wide">
   495→                  Assignees
   496→                </label>
   497→                <div className="flex gap-2 flex-wrap">
   498→                  {/* Unassigned Option */}
   499→                  <button
   500→                    onClick={() => setShowUnassigned(!showUnassigned)}
   501→                    className={`px-3 py-1.5 text-xs font-medium rounded-lg transition-all ${
   502→                      showUnassigned
   503→                        ? 'bg-neutral-500 text-white ring-2 ring-neutral-500 ring-offset-2 ring-offset-white dark:ring-offset-neutral-darkGray'
   504→                        : 'bg-white dark:bg-neutral-charcoal text-text-light-secondary dark:text-text-dark-secondary border border-neutral-lightGray dark:border-neutral-gray hover:border-neutral-500'
   505→                    }`}
   506→                  >
   507→                    Unassigned
   508→                  </button>
   509→
   510→                  {/* Member Avatars */}
   511→                  {members.map((member) => (
   512→                    <button
   513→                      key={member.id}
   514→                      onClick={() => toggleAssignee(member.id)}
   515→                      className={`flex items-center gap-1.5 px-2 py-1.5 text-xs font-medium rounded-lg transition-all ${
   516→                        selectedAssignees.has(member.id)
   517→                          ? 'bg-accent-blue text-white ring-2 ring-accent-blue ring-offset-2 ring-offset-white dark:ring-offset-neutral-darkGray'
   518→                          : 'bg-white dark:bg-neutral-charcoal text-text-light-secondary dark:text-text-dark-secondary border border-neutral-lightGray dark:border-neutral-gray hover:border-accent-blue'
   519→                      }`}
   520→                      title={member.name}
   521→                    >
   522→                      <div
   523→                        className={`w-5 h-5 rounded-full flex items-center justify-center text-white font-bold text-[9px] ${
   524→                          selectedAssignees.has(member.id) ? 'opacity-90' : ''
   525→                        }`}
   526→                        style={{ backgroundColor: member.avatarColor }}
   527→                      >
   528→                        {member.initials}
   529→                      </div>
   530→                      {member.name}
   531→                    </button>
   532→                  ))}
   533→                </div>
   534→              </div>
   535→            )}
   536→          </div>
   537→        )}
   538→
   539→        {/* Results Count */}
   540→        {hasActiveFilters && (
   541→          <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary">
   542→            Showing {filteredTasks.length} of {tasks.length} tasks
   543→          </div>
   544→        )}
   545→      </div>
   546→
   547→      {/* Keyboard shortcuts hint */}
   548→      <div className="mb-3 flex items-center justify-between">
   549→        <div className="text-xs text-text-light-secondary dark:text-text-dark-secondary flex items-center gap-4">
   550→          <span>
   551→            Press <kbd className="px-2 py-0.5 text-xs font-mono bg-neutral-paleGray dark:bg-neutral-darkGray rounded border border-neutral-lightGray dark:border-neutral-gray">?</kbd> for keyboard shortcuts
   552→          </span>
   553→          <span className="hidden md:inline">
   554→            <kbd className="px-2 py-0.5 text-xs font-mono bg-neutral-paleGray dark:bg-neutral-darkGray rounded border border-neutral-lightGray dark:border-neutral-gray">⌘K</kbd> to quick add task
   555→          </span>
   556→        </div>
   557→      </div>
   558→
   559→      {viewMode === 'board' ? (
   560→        <DndContext
   561→          sensors={sensors}
   562→          collisionDetection={closestCorners}
   563→          onDragStart={handleDragStart}
   564→          onDragEnd={handleDragEnd}
   565→        >
   566→          <div className="kanban-board min-h-[500px] flex gap-4 overflow-x-auto pb-4 max-w-full">
   567→            {sortedColumns.map((column, index) => {
   568→              // Dynamic column width: always calculate based on visibleColumns setting
   569→              // If visibleColumns > actual columns, columns will be narrower (leaving space on right)
   570→              // If visibleColumns < actual columns, horizontal scrolling will be enabled
   571→              const columnWidth = `calc((100% - ${(visibleColumns - 1) * 16}px) / ${visibleColumns})`;
   572→
   573→              return (
   574→                <KanbanColumn
   575→                  key={column.id}
   576→                  id={column.id}
   577→                  title={column.title}
   578→                  color={column.color}
   579→                  wipLimit={column.wipLimit}
   580→                  tasks={filteredTasks.filter((task) => task.status === column.id)}
   581→                  selectedTaskId={selectedColumn === index ? selectedTaskId : undefined}
   582→                  columnWidth={columnWidth}
   583→                  onRegisterRef={(ref) => {
   584→                    columnRefs.current[column.id] = ref;
   585→                  }}
   586→                  onRegisterCardRef={(taskId, ref) => {
   587→                    cardRefs.current[taskId] = ref;
   588→                  }}
   589→                  onCardClick={(task, tab) => {
   590→                    setDetailPanelTaskId(task.id);
   591→                    if (tab) setSelectedTab(tab);
   592→                  }}
   593→                  onEditColumn={handleEditColumn}
   594→                />
   595→              );
   596→            })}
   597→          </div>
   598→
   599→          {/* Drag overlay - shows ghost of dragged card */}
   600→          <DragOverlay>
   601→            {activeTask ? (
   602→              <div className="opacity-80 rotate-3 scale-105 transition-transform">
   603→                <KanbanCard task={activeTask} isDragging />
   604→              </div>
   605→            ) : null}
   606→          </DragOverlay>
   607→        </DndContext>
   608→      ) : viewMode === 'list' ? (
   609→        <ListView
   610→          tasks={filteredTasks}
   611→          columns={columns}
   612→          onTaskClick={(task) => setDetailPanelTaskId(task.id)}
   613→        />
   614→      ) : (
   615→        <CalendarView
   616→          tasks={filteredTasks}
   617→          columns={columns}
   618→          onTaskClick={(task) => setDetailPanelTaskId(task.id)}
   619→        />
   620→      )}
   621→
   622→      {/* Keyboard Shortcuts Help Modal */}
   623→      <KeyboardShortcutsHelp isOpen={showHelp} onClose={closeHelp} />
   624→
   625→      {/* Delete Confirmation Dialog */}
   626→      {pendingDeleteTask && (
   627→        <ConfirmDialog
   628→          isOpen={true}
   629→          onClose={cancelDelete}
   630→          onConfirm={confirmDelete}
   631→          title="Delete Task"
   632→          message={`Are you sure you want to delete "${pendingDeleteTask.title}"? This action cannot be undone.`}
   633→          variant="danger"
   634→        />
   635→      )}
   636→
   637→      {/* Column Manager Modal */}
   638→      <ColumnManager
   639→        isOpen={showColumnManager}
   640→        onClose={() => {
   641→          setShowColumnManager(false);
   642→          setColumnManagerInitialId(undefined);
   643→        }}
   644→        initialEditingColumnId={columnManagerInitialId}
   645→      />
   646→
   647→      {/* Toast Notification */}
   648→      {toast && (
   649→        <Toast
   650→          message={toast.message}
   651→          action={toast.showUndo ? { label: 'Undo', onClick: handleUndo } : undefined}
   652→          onClose={() => setToast(null)}
   653→        />
   654→      )}
   655→
   656→      {/* Card Detail Panel */}
   657→      <CardDetailPanel
   658→        task={selectedTask}
   659→        isOpen={!!selectedTask}
   660→        onClose={() => {
   661→          setDetailPanelTaskId(null);
   662→          setSelectedTab('subtasks'); // Reset to default tab
   663→        }}
   664→        onSave={(taskId, updates) => {
   665→          updateTask(taskId, updates);
   666→        }}
   667→        columns={columns}
   668→        initialTab={selectedTab}
   669→        onCardClick={(task) => {
   670→          setDetailPanelTaskId(task.id);
   671→        }}
   672→      />
   673→
   674→      {/* Archived View */}
   675→      <ArchivedView
   676→        isOpen={showArchivedView}
   677→        onClose={() => setShowArchivedView(false)}
   678→      />
   679→
   680→      {/* Quick Add Modal (Phase A: Quick Add Cmd+K) */}
   681→      <QuickAddModal
   682→        isOpen={showQuickAdd}
   683→        onClose={() => setShowQuickAdd(false)}
   684→      />
   685→    </Widget>
   686→  );
   687→};
