   207→
   208→export const useKanbanStore = create<KanbanStore>()(
   209→  persist(
   210→    (set, get) => ({
   211→      // Initial state
   212→      tasks: [],
   213→      columns: DEFAULT_COLUMNS,
   214→      dependencies: [], // Phase 5: Task dependencies
   215→      archivedTasks: [], // Phase A: Archived tasks
   216→      nextCardNumber: 1, // Phase A: Auto-incrementing card number counter
   217→      visibleColumns: 5, // UI: Number of columns visible before scrolling (default: 5)
   218→      undoHistory: [], // Undo system: stores last 5 actions
   219→      baseline: null, // Phase 1.4: Project baseline snapshot
   220→
   221→      // ==================== TASK ACTIONS ====================
   222→
   223→      addTask: (taskData) => {
   224→        const currentNumber = get().nextCardNumber || 1;
   225→
   226→        const newTask: Task = {
   227→          ...taskData,
   228→          id: Date.now().toString(),
   229→          created: new Date().toISOString(),
   230→          cardNumber: currentNumber, // Phase A: Assign auto-incrementing card number
   231→          checklist: [],
   232→          comments: [],
   233→          activityLog: [],
   234→        };
   235→
   236→        set((state) => ({
   237→          tasks: [...state.tasks, newTask],
   238→          nextCardNumber: currentNumber + 1, // Increment counter
   239→        }));
   240→
   241→        // Log creation
   242→        get().logActivity(newTask.id, {
   243→          action: 'created',
   244→        });
   245→
   246→        // P1: Trigger automation rules for 'task.created'
   247→        setTimeout(async () => {
   248→          const { useAutomationStore } = await import('./useAutomationStore');
   249→          const automationStore = useAutomationStore.getState();
   250→          const context: AutomationContext = {
   251→            taskId: newTask.id,
   252→            timestamp: new Date().toISOString(),
   253→          };
   254→
   255→          const logs = await evaluateRules(
   256→            automationStore.rules,
   257→            'task.created',
   258→            newTask,
   259→            context,
   260→            get()
   261→          );
   262→          logs.forEach((log) => automationStore.addExecutionLog(log));
   263→        }, 0);
   264→      },
   265→
   266→      updateTask: (id, updates) => {
   267→        const oldTask = get().tasks.find((t) => t.id === id);
   268→        if (!oldTask) return;
   269→
   270→        // Phase 1.2: Check if date changes trigger dependent shifts
   271→        // Note: This only updates the primary task. Components must call
   272→        // calculateDependentShifts separately and show confirmation dialog
   273→        // before calling applyDependentShifts.
   274→
   275→        set((state) => ({
   276→          tasks: state.tasks.map((task) =>
   277→            task.id === id ? { ...task, ...updates } : task
   278→          ),
   279→        }));
   280→
   281→        // Log updates (track specific fields)
   282→        Object.keys(updates).forEach((field) => {
   283→          if (field !== 'activityLog') { // Don't log the log itself
   284→            get().logActivity(id, {
   285→              action: 'updated',
   286→              field,
   287→              oldValue: String(oldTask[field as keyof Task] ?? ''),
   288→              newValue: String(updates[field as keyof Task] ?? ''),
   289→            });
   290→          }
   291→        });
   292→      },
   293→
   294→      deleteTask: (id) =>
   295→        set((state) => ({
   296→          tasks: state.tasks.filter((task) => task.id !== id),
   297→        })),
   298→
   299→      moveTask: (id, newStatus) => {
   300→        const oldTask = get().tasks.find((t) => t.id === id);
   301→        if (!oldTask) return;
   302→
   303→        // PHASE 5 PART 6: Validate dependencies before moving to "done"
   304→        if (newStatus === 'done') {
   305→          const blockers = get().getBlockers(id);
   306→          const incompleteBlockers = blockers.filter((b) => b.status !== 'done');
   307→
   308→          if (incompleteBlockers.length > 0) {
   309→            log.warn('Cannot complete task: blocked by incomplete tasks', {
   310→              taskId: id,
   311→              taskTitle: oldTask.title,
   312→              blockerCount: incompleteBlockers.length
   313→            });
   314→            // TODO: Show toast notification in UI
   315→            return; // Prevent move
   316→          }
   317→        }
   318→
   319→        // PHASE A: Track when task is completed (for auto-archive)
   320→        const updates: Partial<Task> = { status: newStatus };
   321→        if (newStatus === 'done' && oldTask.status !== 'done') {
   322→          updates.lastCompletedAt = new Date().toISOString();
   323→        }
   324→
   325→        // P1: AUTO-GENERATE NEXT RECURRING INSTANCE
   326→        // If completing a recurring task instance, generate next occurrence
   327→        const isCompletingRecurringInstance = newStatus === 'done' && oldTask.recurrenceId;
   328→
   329→        set((state) => ({
   330→          tasks: state.tasks.map((task) =>
   331→            task.id === id ? { ...task, ...updates } : task
   332→          ),
   333→        }));
   334→
   335→        // Generate next instance after state update (avoid mutation during update)
   336→        if (isCompletingRecurringInstance) {
   337→          setTimeout(() => {
   338→            // Pass the completed task instance for recurFromCompletion calculation
   339→            const completedTask = get().tasks.find((t) => t.id === id);
   340→            get().generateNextRecurringInstance(oldTask.recurrenceId!, completedTask);
   341→          }, 0);
   342→        }
   343→
   344→        // Log move
   345→        get().logActivity(id, {
   346→          action: 'moved',
   347→          field: 'status',
   348→          oldValue: oldTask.status,
   349→          newValue: newStatus,
   350→        });
   351→
   352→        // P1: Trigger automation rules for 'task.moved' and potentially 'task.completed'
   353→        setTimeout(async () => {
   354→          const { useAutomationStore } = await import('./useAutomationStore');
   355→          const automationStore = useAutomationStore.getState();
   356→          const updatedTask = get().tasks.find((t) => t.id === id);
   357→          if (!updatedTask) return;
   358→
   359→          const context: AutomationContext = {
   360→            taskId: id,
   361→            previousStatus: oldTask.status,
   362→            newStatus,
   363→            timestamp: new Date().toISOString(),
   364→          };
   365→
   366→          // Trigger 'task.moved' for all status changes
   367→          const movedLogs = await evaluateRules(
   368→            automationStore.rules,
   369→            'task.moved',
   370→            updatedTask,
   371→            context,
   372→            get()
   373→          );
   374→          movedLogs.forEach((log) => automationStore.addExecutionLog(log));
   375→
   376→          // Also trigger 'task.completed' if moved to done
   377→          if (newStatus === 'done') {
   378→            const completedLogs = await evaluateRules(
   379→              automationStore.rules,
   380→              'task.completed',
   381→              updatedTask,
   382→              context,
   383→              get()
   384→            );
   385→            completedLogs.forEach((log) => automationStore.addExecutionLog(log));
   386→          }
   387→        }, 0);
   388→      },
   389→
   390→      getTasksByStatus: (status) => {
   391→        return get().tasks.filter((task) => task.status === status);
   392→      },
   393→
   394→      getFilteredTasks: () => {
   395→        const { activeProjectIds } = useProjectContextStore.getState();
   396→        const tasks = get().tasks;
   397→
   398→        // "All" mode - no filter applied
   399→        if (activeProjectIds.length === 0) return tasks;
   400→
   401→        // Filter tasks that have ANY of the active project IDs
   402→        return tasks.filter((task) =>
   403→          task.projectIds.some((pid) => activeProjectIds.includes(pid))
   404→        );
   405→      },
   406→
   407→      // ==================== RECURRING TASK ACTIONS (P1) ====================
   408→
   409→      setTaskRecurrence: (taskId, recurrence) => {
   410→        const task = get().tasks.find((t) => t.id === taskId);
   411→        if (!task) {
   412→          log.warn('Task not found for recurrence', { taskId });
   413→          return;
   414→        }
   415→
   416→        // Mark as recurring parent and calculate next occurrence
   417→        const updates: Partial<Task> = {
   418→          recurrence,
   419→          isRecurringParent: recurrence ? true : undefined,
   420→          nextOccurrence: recurrence ? updateNextOccurrence({ ...task, recurrence }) : undefined,
   421→        };
   422→
   423→        get().updateTask(taskId, updates);
   424→
   425→        log.info('Task recurrence set', { taskId, frequency: recurrence?.frequency });
   426→      },
   427→
   428→      generateNextRecurringInstance: (parentTaskId, lastCompletedInstance) => {
   429→        const parentTask = get().tasks.find((t) => t.id === parentTaskId);
   430→        if (!parentTask || !parentTask.isRecurringParent) {
   431→          log.warn('Not a recurring parent task', { parentTaskId });
   432→          return;
   433→        }
   434→
   435→        // Check if we should generate next instance
   436→        if (!shouldGenerateNextInstance(parentTask, get().tasks)) {
   437→          log.debug('Next instance not needed yet', { parentTaskId });
   438→          return;
   439→        }
   440→
   441→        // Generate new instance (pass completed instance for recurFromCompletion)
   442→        const instance = generateNextInstance(parentTask, lastCompletedInstance);
   443→        if (!instance) {
   444→          log.debug('No more instances to generate (series ended)', { parentTaskId });
   445→          return;
   446→        }
   447→
   448→        // Add instance to tasks
   449→        set((state) => ({
   450→          tasks: [...state.tasks, instance],
   451→        }));
   452→
   453→        // Update parent's nextOccurrence
   454→        const nextOccurrence = updateNextOccurrence(parentTask);
   455→        get().updateTask(parentTaskId, { nextOccurrence });
   456→
   457→        log.info('Generated recurring task instance', {
   458→          parentId: parentTaskId,
   459→          instanceId: instance.id,
   460→          dueDate: instance.dueDate,
   461→        });
   462→      },
   463→
   464→      getRecurringTaskInstances: (parentTaskId) => {
   465→        return getTaskInstances(
   466→          get().tasks.find((t) => t.id === parentTaskId)!,
   467→          get().tasks
   468→        );
   469→      },
   470→
   471→      // ==================== COLUMN ACTIONS ====================
   472→
   473→      addColumn: (columnData) => {
   474→        const columns = get().columns;
   475→        const newColumn: KanbanColumn = {
   476→          ...columnData,
   477→          id: `col-${Date.now()}`,
   478→          order: columns.length,
   479→        };
   480→
   481→        set((state) => ({
   482→          columns: [...state.columns, newColumn],
   483→        }));
   484→      },
   485→
   486→      updateColumn: (id, updates) => {
   487→        set((state) => ({
   488→          columns: state.columns.map((col) =>
   489→            col.id === id ? { ...col, ...updates } : col
   490→          ),
   491→        }));
   492→      },
   493→
   494→      deleteColumn: (id) => {
   495→        const state = get();
   496→        const columnToDelete = state.columns.find(col => col.id === id);
   497→
   498→        if (!columnToDelete) {
   499→          log.warn('Column not found for deletion', { columnId: id });
   500→          return;
   501→        }
   502→
   503→        // Save undo entry BEFORE making changes
   504→        get().addToUndoHistory({
   505→          action: 'deleteColumn',
   506→          description: `Deleted column '${columnToDelete.title}'`,
   507→          previousState: {
   508→            columns: state.columns,
   509→            tasks: state.tasks,
   510→          },
   511→        });
   512→
   513→        // Find first remaining column (fallback, not hardcoded 'backlog')
   514→        const firstRemainingColumn = state.columns.find(col => col.id !== id);
   515→
   516→        if (!firstRemainingColumn) {
   517→          log.error('Cannot delete last column');
   518→          return;
   519→        }
   520→
   521→        // Move all tasks from deleted column to first remaining column
   522→        set((state) => ({
   523→          columns: state.columns.filter((col) => col.id !== id),
   524→          tasks: state.tasks.map((task) =>
   525→            task.status === id as TaskStatus
   526→              ? { ...task, status: firstRemainingColumn.id as TaskStatus }
   527→              : task
   528→          ),
   529→        }));
   530→      },
   531→
   532→      reorderColumns: (columnIds) => {
   533→        const columns = get().columns;
   534→        const reordered = columnIds
   535→          .map((id) => columns.find((col) => col.id === id))
   536→          .filter((col): col is KanbanColumn => col !== undefined)
   537→          .map((col, index) => ({ ...col, order: index }));
   538→
   539→        set({ columns: reordered });
   540→      },
   541→
   542→      replaceAllColumns: (newColumns: Omit<KanbanColumn, 'id' | 'order'>[]) => {
   543→        const state = get();
   544→
   545→        // Save undo entry BEFORE making changes
   546→        get().addToUndoHistory({
   547→          action: 'replaceAllColumns',
   548→          description: `Applied template`,
   549→          previousState: {
   550→            columns: state.columns,
   551→            tasks: state.tasks,
   552→          },
   553→        });
   554→
   555→        // Generate new columns with fresh IDs and correct order
   556→        const columns: KanbanColumn[] = newColumns.map((col, index) => ({
   557→          ...col,
   558→          id: `col-${Date.now()}-${index}`,
   559→          order: index,
   560→        }));
   561→
   562→        if (columns.length === 0) {
   563→          log.error('No columns provided for replacement');
   564→          return;
   565→        }
   566→
   567→        // Smart mapping: Try to preserve task positions based on column titles
   568→        const tasks = state.tasks.map(task => {
   569→          const oldColumn = state.columns.find(c => c.id === task.status);
   570→          if (!oldColumn) {
   571→            // Task has invalid status, move to first column
   572→            return { ...task, status: columns[0].id as TaskStatus };
   573→          }
   574→
   575→          // Try exact match first (case-insensitive)
   576→          let newColumn = columns.find(c =>
   577→            c.title.toLowerCase() === oldColumn.title.toLowerCase()
   578→          );
   579→
   580→          // If no exact match, try partial match (contains)
   581→          if (!newColumn) {
   582→            newColumn = columns.find(c =>
   583→              c.title.toLowerCase().includes(oldColumn.title.toLowerCase()) ||
   584→              oldColumn.title.toLowerCase().includes(c.title.toLowerCase())
   585→            );
   586→          }
   587→
   588→          // Fallback: first column
   589→          if (!newColumn) {
   590→            newColumn = columns[0];
   591→          }
   592→
   593→          return { ...task, status: newColumn.id as TaskStatus };
   594→        });
   595→
   596→        set({ columns, tasks });
   597→      },
   598→
   599→      // ==================== CHECKLIST ACTIONS ====================
   600→
   601→      addChecklistItem: (taskId, text) => {
   602→        const task = get().tasks.find((t) => t.id === taskId);
   603→        if (!task) return;
   604→
   605→        const newItem: ChecklistItem = {
   606→          id: `check-${Date.now()}`,
   607→          text,
   608→          completed: false,
   609→          order: (task.checklist || []).length,
   610→          createdAt: new Date().toISOString(),
   611→        };
   612→
   613→        set((state) => ({
   614→          tasks: state.tasks.map((t) =>
   615→            t.id === taskId
   616→              ? { ...t, checklist: [...(t.checklist || []), newItem] }
   617→              : t
   618→          ),
   619→        }));
   620→
   621→        // Log checklist update
   622→        get().logActivity(taskId, {
   623→          action: 'checklist_updated',
   624→          newValue: `Added: ${text}`,
   625→        });
   626→      },
   627→
   628→      updateChecklistItem: (taskId, itemId, updates) => {
   629→        set((state) => ({
   630→          tasks: state.tasks.map((t) =>
   631→            t.id === taskId
   632→              ? {
   633→                  ...t,
   634→                  checklist: (t.checklist || []).map((item) =>
   635→                    item.id === itemId ? { ...item, ...updates } : item
   636→                  ),
   637→                }
   638→              : t
   639→          ),
   640→        }));
   641→      },
   642→
   643→      deleteChecklistItem: (taskId, itemId) => {
   644→        const task = get().tasks.find((t) => t.id === taskId);
   645→        if (!task) return;
   646→
   647→        const item = task.checklist?.find((i) => i.id === itemId);
   648→        if (!item) return;
   649→
   650→        set((state) => ({
   651→          tasks: state.tasks.map((t) =>
   652→            t.id === taskId
   653→              ? {
   654→                  ...t,
   655→                  checklist: (t.checklist || []).filter((i) => i.id !== itemId),
   656→                }
   657→              : t
   658→          ),
   659→        }));
   660→
   661→        // Log deletion
