  1124→      // ==================== PHASE 5: DEPENDENCY ACTIONS ====================
  1125→
  1126→      addDependency: (taskId, dependency) => {
  1127→        // Prevent self-dependency
  1128→        if (taskId === dependency.taskId) {
  1129→          log.error('Task cannot depend on itself', { taskId });
  1130→          return;
  1131→        }
  1132→
  1133→        // Check for circular dependency
  1134→        const task = get().tasks.find(t => t.id === taskId);
  1135→        if (!task) {
  1136→          log.error('Task not found', { taskId });
  1137→          return;
  1138→        }
  1139→
  1140→        const wouldCreateCycle = (currentTaskId: string, blockerTaskId: string, visited = new Set<string>()): boolean => {
  1141→          if (currentTaskId === blockerTaskId) return true;
  1142→          if (visited.has(currentTaskId)) return false; // Already checked
  1143→
  1144→          visited.add(currentTaskId);
  1145→
  1146→          // Get the blocker task's dependencies
  1147→          const blockerTask = get().tasks.find(t => t.id === blockerTaskId);
  1148→          if (!blockerTask || !blockerTask.dependencies) return false;
  1149→
  1150→          // Check if blocker depends on current (directly or indirectly)
  1151→          return blockerTask.dependencies.some(dep => wouldCreateCycle(currentTaskId, dep.taskId, visited));
  1152→        };
  1153→
  1154→        if (wouldCreateCycle(taskId, dependency.taskId)) {
  1155→          log.error('Circular dependency detected', { taskId, dependsOn: dependency.taskId });
  1156→          return;
  1157→        }
  1158→
  1159→        // Add dependency to task
  1160→        set((state) => ({
  1161→          tasks: state.tasks.map(t => {
  1162→            if (t.id === taskId) {
  1163→              const existingDeps = t.dependencies || [];
  1164→              // Check if dependency already exists
  1165→              if (existingDeps.some(d => d.taskId === dependency.taskId)) {
  1166→                log.warn('Dependency already exists', { taskId, dependsOn: dependency.taskId });
  1167→                return t;
  1168→              }
  1169→              return {
  1170→                ...t,
  1171→                dependencies: [...existingDeps, dependency],
  1172→              };
  1173→            }
  1174→            return t;
  1175→          }),
  1176→        }));
  1177→
  1178→        // Log activity with dependency type info
  1179→        const dependencyLabel = {
  1180→          'finish-to-start': 'FS (Finish-to-Start)',
  1181→          'start-to-start': 'SS (Start-to-Start)',
  1182→          'finish-to-finish': 'FF (Finish-to-Finish)',
  1183→          'start-to-finish': 'SF (Start-to-Finish)',
  1184→        }[dependency.type];
