  1188→          : '';
  1189→
  1190→        get().logActivity(taskId, {
  1191→          action: 'created',
  1192→          field: 'dependency',
  1193→          newValue: `Depends on task ${dependency.taskId} (${dependencyLabel}${lagLabel})`,
  1194→        });
  1195→      },
