  1296→        // Log activity for each shifted task
  1297→        shifts.forEach(shift => {
  1298→          get().logActivity(shift.taskId, {
  1299→            action: 'updated',
  1300→            field: 'dates',
  1301→            newValue: shift.reason,
  1302→          });
  1303→        });
  1304→
  1305→        log.info('Dependent shifts applied successfully');
  1306→      },
  1307→
  1308→      // ==================== PHASE 1.3: CRITICAL PATH ANALYSIS ====================
  1309→
  1310→      getCriticalPath: () => {
  1311→        const tasks = get().tasks;
  1312→        return calculateCriticalPath(tasks);
  1313→      },
  1314→
  1315→      getTaskSlack: (taskId) => {
  1316→        const tasks = get().tasks;
  1317→        const task = tasks.find(t => t.id === taskId);
  1318→        if (!task) return 0;
  1319→        return calculateSlack(task, tasks);
  1320→      },
  1321→
  1322→      // ==================== PHASE 1.4: BASELINE COMPARISON ====================
  1323→
  1324→      setBaseline: () => {
  1325→        const tasks = get().tasks;
  1326→        const baseline = createBaselineSnapshot(tasks);
  1327→        set({ baseline });
  1328→        log.info('Baseline set', { taskCount: baseline.tasks.length, setAt: baseline.setAt });
  1329→      },
  1330→
  1331→      clearBaseline: () => {
  1332→        set({ baseline: null });
  1333→        log.info('Baseline cleared');
  1334→      },
  1335→
  1336→      getBaseline: () => {
  1337→        return get().baseline || null;
  1338→      },
  1339→
  1340→      // ==================== PHASE A: ARCHIVE ACTIONS ====================
  1341→
  1342→      archiveTask: (id) => {
  1343→        const task = get().tasks.find((t) => t.id === id);
  1344→        if (!task) return;
  1345→
  1346→        const archivedTask: Task = {
  1347→          ...task,
  1348→          archivedAt: new Date().toISOString(),
  1349→        };
  1350→
  1351→        set((state) => ({
  1352→          tasks: state.tasks.filter((t) => t.id !== id),
  1353→          archivedTasks: [...(state.archivedTasks || []), archivedTask],
  1354→        }));
  1355→
  1356→        // Log archive action
  1357→        get().logActivity(id, {
  1358→          action: 'updated',
  1359→          field: 'archived',
  1360→          newValue: 'true',
  1361→        });
  1362→      },
  1363→
  1364→      restoreTask: (id) => {
  1365→        const archivedTask = get().archivedTasks?.find((t) => t.id === id);
  1366→        if (!archivedTask) return;
  1367→
  1368→        // Remove archivedAt field when restoring
  1369→        const { archivedAt, ...restoredTask } = archivedTask;
  1370→
  1371→        set((state) => ({
  1372→          archivedTasks: (state.archivedTasks || []).filter((t) => t.id !== id),
  1373→          tasks: [...state.tasks, restoredTask as Task],
  1374→        }));
  1375→
  1376→        // Log restore action
  1377→        get().logActivity(id, {
  1378→          action: 'updated',
  1379→          field: 'archived',
  1380→          oldValue: 'true',
  1381→          newValue: 'false',
  1382→        });
  1383→      },
  1384→
  1385→      deleteArchivedTask: (id) => {
  1386→        set((state) => ({
  1387→          archivedTasks: (state.archivedTasks || []).filter((t) => t.id !== id),
  1388→        }));
  1389→      },
  1390→
  1391→      getArchivedTasks: () => {
  1392→        return (get().archivedTasks || []).sort((a, b) => {
  1393→          // Sort by archive date (most recent first)
  1394→          const dateA = new Date(a.archivedAt || 0).getTime();
  1395→          const dateB = new Date(b.archivedAt || 0).getTime();
  1396→          return dateB - dateA;
  1397→        });
  1398→      },
  1399→
  1400→      autoArchiveCompletedTasks: () => {
  1401→        const now = new Date();
  1402→        const fourteenDaysAgo = new Date(now.getTime() - 14 * 24 * 60 * 60 * 1000);
  1403→
  1404→        const tasksToArchive = get().tasks.filter((task) => {
  1405→          // Only archive tasks in "done" status
  1406→          if (task.status !== 'done') return false;
  1407→
  1408→          // Check if task has been completed for > 14 days
  1409→          if (task.lastCompletedAt) {
  1410→            const completedDate = new Date(task.lastCompletedAt);
  1411→            return completedDate < fourteenDaysAgo;
  1412→          }
  1413→
  1414→          return false;
  1415→        });
  1416→
  1417→        // Archive each task
  1418→        tasksToArchive.forEach((task) => {
  1419→          get().archiveTask(task.id);
  1420→        });
  1421→
  1422→        if (tasksToArchive.length > 0) {
  1423→          log.info('Auto-archived completed tasks', { count: tasksToArchive.length });
  1424→        }
  1425→      },
  1426→
  1427→      // ==================== PHASE B: TIME TRACKING ====================
  1428→
  1429→      startTimer: (taskId) => {
  1430→        const now = new Date().toISOString();
  1431→
  1432→        set((state) => ({
  1433→          tasks: state.tasks.map((task) => {
  1434→            if (task.id === taskId) {
  1435→              return {
  1436→                ...task,
  1437→                timeTracking: {
  1438→                  estimated: task.timeTracking?.estimated,
  1439→                  actual: task.timeTracking?.actual || 0,
  1440→                  activeTimerStart: now,
  1441→                  timerHistory: task.timeTracking?.timerHistory || [],
  1442→                },
  1443→              };
  1444→            }
  1445→            return task;
  1446→          }),
  1447→        }));
  1448→
  1449→        // Log timer start
  1450→        get().logActivity(taskId, {
  1451→          action: 'updated',
  1452→          field: 'timer',
  1453→          newValue: 'started',
  1454→        });
  1455→      },
  1456→
  1457→      stopTimer: (taskId) => {
  1458→        const now = new Date().toISOString();
  1459→        const state = get();
  1460→        const task = state.tasks.find((t) => t.id === taskId);
  1461→
  1462→        if (!task || !task.timeTracking?.activeTimerStart) {
  1463→          log.warn('No active timer for task', { taskId });
  1464→          return;
  1465→        }
  1466→
  1467→        const startTime = new Date(task.timeTracking.activeTimerStart);
  1468→        const endTime = new Date(now);
  1469→        const duration = Math.floor((endTime.getTime() - startTime.getTime()) / 1000); // seconds
  1470→
  1471→        set((state) => ({
  1472→          tasks: state.tasks.map((t) => {
  1473→            if (t.id === taskId && t.timeTracking) {
  1474→              const newEntry = {
  1475→                id: crypto.randomUUID(),
  1476→                startTime: task.timeTracking!.activeTimerStart!,
  1477→                endTime: now,
  1478→                duration,
  1479→              };
  1480→
  1481→              return {
  1482→                ...t,
  1483→                timeTracking: {
  1484→                  estimated: t.timeTracking.estimated,
  1485→                  actual: t.timeTracking.actual + duration,
  1486→                  activeTimerStart: undefined,
  1487→                  timerHistory: [...(t.timeTracking.timerHistory || []), newEntry],
  1488→                },
  1489→              };
  1490→            }
  1491→            return t;
  1492→          }),
  1493→        }));
  1494→
  1495→        // Log timer stop
  1496→        get().logActivity(taskId, {
  1497→          action: 'updated',
  1498→          field: 'timer',
  1499→          oldValue: 'running',
  1500→          newValue: `stopped (+${Math.floor(duration / 60)}m)`,
  1501→        });
  1502→      },
  1503→
  1504→      updateTimeEstimate: (taskId, hours) => {
  1505→        set((state) => ({
  1506→          tasks: state.tasks.map((task) => {
  1507→            if (task.id === taskId) {
  1508→              return {
  1509→                ...task,
  1510→                timeTracking: {
  1511→                  estimated: hours,
  1512→                  actual: task.timeTracking?.actual || 0,
  1513→                  activeTimerStart: task.timeTracking?.activeTimerStart,
  1514→                  timerHistory: task.timeTracking?.timerHistory || [],
  1515→                },
  1516→              };
  1517→            }
  1518→            return task;
  1519→          }),
  1520→        }));
  1521→
  1522→        // Log estimate update
  1523→        get().logActivity(taskId, {
  1524→          action: 'updated',
  1525→          field: 'time_estimate',
  1526→          newValue: `${hours}h`,
  1527→        });
  1528→      },
  1529→
  1530→      // ==================== PHASE B: CUSTOM FIELDS ====================
  1531→
  1532→      updateEffort: (taskId, effort) => {
  1533→        set((state) => ({
  1534→          tasks: state.tasks.map((task) => {
  1535→            if (task.id === taskId) {
  1536→              const oldEffort = task.effort;
  1537→
  1538→              // Log activity if changed
  1539→              if (oldEffort !== effort) {
  1540→                setTimeout(() => {
  1541→                  get().logActivity(taskId, {
  1542→                    action: 'updated',
  1543→                    field: 'effort',
  1544→                    oldValue: oldEffort?.toString(),
  1545→                    newValue: effort?.toString(),
  1546→                  });
  1547→                }, 0);
  1548→              }
  1549→
  1550→              return { ...task, effort };
  1551→            }
  1552→            return task;
  1553→          }),
  1554→        }));
  1555→      },
  1556→
  1557→      updateCustomStatus: (taskId, customStatus) => {
  1558→        set((state) => ({
  1559→          tasks: state.tasks.map((task) => {
  1560→            if (task.id === taskId) {
  1561→              const oldStatus = task.customStatus;
  1562→
  1563→              // Log activity if changed
  1564→              if (oldStatus !== customStatus) {
  1565→                setTimeout(() => {
  1566→                  get().logActivity(taskId, {
  1567→                    action: 'updated',
  1568→                    field: 'custom_status',
  1569→                    oldValue: oldStatus,
  1570→                    newValue: customStatus,
  1571→                  });
  1572→                }, 0);
  1573→              }
  1574→
  1575→              return { ...task, customStatus };
  1576→            }
  1577→            return task;
  1578→          }),
  1579→        }));
  1580→      },
  1581→
  1582→      // ==================== BULK IMPORT ====================
  1583→
  1584→      bulkImportTasks: (importedTasks: Array<{
  1585→        title: string;
  1586→        description?: string;
  1587→        dueDate?: string;
  1588→        priority?: TaskPriority;
  1589→        tags?: string[];
  1590→        status?: TaskStatus;
  1591→        completed?: boolean;
  1592→        estimatedHours?: number;
  1593→        progress?: number;
  1594→        checklist?: Array<{ text: string; completed: boolean }>;
  1595→      }>) => {
  1596→        const now = new Date().toISOString();
  1597→        const importedTaskIds: string[] = [];
  1598→        const newTags: string[] = [];
  1599→
  1600→        // Get next card number
  1601→        let nextCardNumber = get().nextCardNumber || 1;
  1602→
  1603→        // Process tasks
  1604→        const newTasks: Task[] = importedTasks.map((imported) => {
  1605→          const taskId = crypto.randomUUID();
  1606→          importedTaskIds.push(taskId);
  1607→
  1608→          // Convert checklist to ChecklistItem format if provided
  1609→          const checklist: ChecklistItem[] | undefined = imported.checklist?.map((item, idx) => ({
  1610→            id: crypto.randomUUID(),
  1611→            text: item.text,
  1612→            completed: item.completed,
  1613→            order: idx,
  1614→            createdAt: now,
  1615→          }));
  1616→
  1617→          // Track new tags
  1618→          imported.tags?.forEach(tag => {
  1619→            if (tag && !newTags.includes(tag)) {
  1620→              newTags.push(tag);
  1621→            }
  1622→          });
  1623→
  1624→          const task: Task = {
  1625→            id: taskId,
  1626→            title: imported.title,
  1627→            description: imported.description || '',
  1628→            status: imported.completed ? 'done' : (imported.status || 'todo'),
  1629→            created: now,
  1630→            startDate: null,
  1631→            dueDate: imported.dueDate || null,
  1632→            priority: imported.priority || 'medium',
  1633→            tags: imported.tags || [],
  1634→            cardNumber: nextCardNumber++,
  1635→            checklist,
  1636→            estimatedHours: imported.estimatedHours,
  1637→            progress: imported.progress,
  1638→            projectIds: [],
  1639→          };
  1640→
  1641→          return task;
  1642→        });
  1643→
  1644→        // Update state
  1645→        set((state) => ({
  1646→          tasks: [...state.tasks, ...newTasks],
  1647→          nextCardNumber,
  1648→        }));
  1649→
  1650→        log.info('Bulk imported tasks', {
  1651→          count: newTasks.length,
  1652→          newTags: newTags.length,
  1653→        });
  1654→
  1655→        return {
  1656→          success: true,
  1657→          tasksImported: newTasks.length,
  1658→          tagsCreated: newTags,
  1659→          errors: [],
  1660→          warnings: [],
  1661→        };
  1662→      },
  1663→
  1664→      // ==================== UI PREFERENCES ====================
  1665→
  1666→      setVisibleColumns: (count) => {
  1667→        // Validate input (3-7 columns)
  1668→        const validCount = Math.min(Math.max(count, 3), 7);
  1669→        set({ visibleColumns: validCount });
  1670→      },
  1671→
  1672→      // ==================== CARD TEMPLATES ====================
  1673→
  1674→      getCardTemplates: () => {
  1675→        return DEFAULT_CARD_TEMPLATES;
  1676→      },
  1677→    }),
  1678→    {
  1679→      name: 'kanban-tasks',
  1680→      storage: createJSONStorage(() => createSyncedStorage()),
  1681→      version: 3, // v3: Add projectIds for global project context filter
  1682→      migrate: (persistedState: any, version: number) => {
  1683→        let state = persistedState;
  1684→
  1685→        // Migration v1 -> v2: Migrate from global SimpleTaskDependency[] to task-level TaskDependency[]
  1686→        if (version < 2 && needsMigration(state)) {
  1687→          log.info('Migrating dependencies from global array to task level');
  1688→          const migratedTasks = migrateDependenciesToTaskLevel(
  1689→            state.tasks || [],
  1690→            state.dependencies || []
  1691→          );
  1692→
  1693→          state = {
  1694→            ...state,
  1695→            tasks: migratedTasks,
  1696→            dependencies: undefined, // Remove old dependencies field
  1697→          };
  1698→        }
  1699→
  1700→        // Migration v2 -> v3: Add projectIds field to all tasks
  1701→        if (version < 3 && state.tasks) {
  1702→          log.info('Adding projectIds field to all tasks');
  1703→          state = {
  1704→            ...state,
  1705→            tasks: state.tasks.map((task: any) => ({
  1706→              ...task,
  1707→              projectIds: task.projectIds ?? [],
  1708→            })),
  1709→            archivedTasks: state.archivedTasks?.map((task: any) => ({
  1710→              ...task,
  1711→              projectIds: task.projectIds ?? [],
  1712→            })),
  1713→          };
  1714→        }
  1715→
  1716→        return state;
  1717→      },
  1718→    }
  1719→  )
